dtsPropsFor.Alert:
/** Alert / Callout for form- and page-level messages. Compose: Alert (root) wrapping an AlertTitle and an AlertDescription. Tokens only (brand / muted / destructive families) — no new theme values. `error` is announced assertively (role="alert"); the other tones use role="status", and an explicit `role` prop wins. */
/** Message tone. @default 'info' */
tone?: 'info' | 'success' | 'warning' | 'error';
role?: 'alert' | 'status';
children?: React.ReactNode;
className?: string;
/** Plus all native <div> attributes. */
[key: string]: unknown;

dtsPropsFor.Badge:
/** Status pill for rows/lists — a small rounded label. Tokens only; no new theme values. */
/** Visual style variant. @default 'default' */
variant?: 'default' | 'secondary' | 'destructive' | 'outline';
children?: React.ReactNode;
className?: string;
/** Plus all native <span> attributes. */
[key: string]: unknown;

dtsPropsFor.Button:
/** Visual style variant. @default 'default' */
variant?: 'default' | 'destructive' | 'outline' | 'secondary' | 'ghost' | 'link';
/** Size preset. @default 'default' */
size?: 'default' | 'wide' | 'sm' | 'lg' | 'pill' | 'icon' | 'icon-sm' | 'icon-lg';
/** Render as the child element via Radix Slot instead of a native <button>. @default false */
asChild?: boolean;
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: 'button' | 'submit' | 'reset';
onClick?: React.MouseEventHandler<HTMLButtonElement>;
/** Plus all native <button> attributes. */
[key: string]: unknown;

dtsPropsFor.Card:
/** Compound card surface promoting the `bg-card text-card-foreground rounded-lg border` idiom. Compose: Card (root) wrapping an optional CardHeader (holding CardTitle + CardDescription), a CardContent, and an optional CardFooter. Tokens only — no hardcoded colors or radii. */
children?: React.ReactNode;
className?: string;
/** Plus all native <div> attributes. */
[key: string]: unknown;

dtsPropsFor.Checkbox:
/** Controlled checked state; 'indeterminate' for a mixed state. */
checked?: boolean | 'indeterminate';
/** Uncontrolled initial checked state. */
defaultChecked?: boolean;
onCheckedChange?: (checked: boolean | 'indeterminate') => void;
disabled?: boolean;
required?: boolean;
name?: string;
value?: string;
id?: string;
className?: string;
