'aria-invalid'?: boolean | 'true' | 'false';

dtsPropsFor.Dialog:
/** Shared modal overlay (Radix). The deliberate ADR 023 exception for transient client overlays (⌘K palette, confirm step) — not content-bearing or bookmarkable; reach for a page when the content should be linkable. Compose: Dialog (root) wrapping a DialogTrigger, an optional DialogOverlay, and a DialogContent holding a DialogTitle (+ optional DialogDescription) and a DialogClose. Tokens only (popover / border). */
/** Controlled open state. */
open?: boolean;
/** Uncontrolled initial open state. */
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
/** Trap focus and block outside interaction while open. @default true */
modal?: boolean;
children?: React.ReactNode;

