dtsPropsFor.Skeleton:
/** Muted, pulsing placeholder for loading/empty states. Size and shape it with utility classes (`h-4 w-32`, `rounded-full`, …); the base supplies the `bg-muted` fill, a default `rounded`, and the pulse animation (dropped under prefers-reduced-motion). Tokens only. */
className?: string;
/** Plus all native <div> attributes. */
[key: string]: unknown;

dtsPropsFor.Spinner:
/** Standalone inline loading indicator: a spinning `update` icon in a `role="status"` region (rotation dropped under prefers-reduced-motion). Backs any loading/empty state; StatusButton composes it for its pending state. */
/** Accessible label for the status region / icon. @default 'loading' */
title?: string;
className?: string;
/** Plus all native <div> attributes. */
[key: string]: unknown;

